const input = $input.first().json.body || $input.first().json;
const errors = input.errors || [];
const pernrList = input.pernr_list || [];
const categories = input.categories || [];
const triggeredBy = input.triggered_by || 'unknown';

console.log(`[AGENT FIX] Triggered by ${triggeredBy}, errors=${errors.length}, categories=${categories.join(',')}`);

// Build agent message
const agentMessage = `Analyze these ${errors.length} BUPA sync errors and propose fixes. For each error, provide: error category, root cause, proposed fix action, target table/field, current value, proposed value, and confidence score (0-1).\n\nErrors:\n${JSON.stringify(errors, null, 2)}`;

return [{ json: { agent_message: agentMessage, errors, pernr_list: pernrList, categories, triggered_by: triggeredBy } }];

const request = $('Parse Request').first().json;
const agentResult = $('Call AI Agent').first().json;

// Extract agent response content
let agentResponse = '';
if (agentResult.result && agentResult.result.content) {
  agentResponse = agentResult.result.content;
} else if (agentResult.content) {
  agentResponse = agentResult.content;
} else {
  agentResponse = JSON.stringify(agentResult);
}

const result = {
  status: 'completed',
  action: 'agent_fix',
  errors_analyzed: request.errors.length,
  pernr_count: request.pernr_list.length,
  agent_response: agentResponse,
  triggered_by: request.triggered_by,
  completed_at: new Date().toISOString()
};

console.log(`[AGENT FIX COMPLETE] ${request.errors.length} errors analyzed`);

return [{ json: result }];
